        public void CompareExcelFiles(string ExcelFilePath)
        {
        	var outputFolder = Path.Combine(OutputRootFolder, OutputSubFolder, ProjectName, ProjectSubFolder);
        	var refFolder = Path.Combine(ReferenceFilesFolder, ProjectName, ReferenceFilesSubFolder);
        	Report.Log(ReportLevel.Info, "Output folder: " + outputFolder);
        	Report.Log(ReportLevel.Info, "Reference folder: " + refFolder);  	
        	var outputFiles = Directory.EnumerateFiles(outputFolder, "*.xls*", SearchOption.AllDirectories).Where(x => !Path.GetFileName(x).StartsWith("~")).ToList();
        	var referenceFiles = Directory.EnumerateFiles(refFolder, "*.xls*", SearchOption.AllDirectories).Where(x => !Path.GetFileName(x).StartsWith("~")).ToList();
        	     
			try 
			{
	        	if (outputFiles.Count != referenceFiles.Count) 
	        	{
	        		Report.Log(ReportLevel.Info, "Output Files:\r\n" + string.Join("\r\n", outputFiles.OrderBy(x => x)));
	        		Report.Log(ReportLevel.Info, "Reference Files:\r\n" + string.Join("\r\n", referenceFiles.OrderBy(x => x)));
	        		throw new ArgumentException("There are a different number of files in the output folder than the reference files folder");
	        	}
	        	else 
	        	{
	        		for (int i = 0; i < outputFiles.Count; i++) 
	        		{
	        			Report.Log(ReportLevel.Info, "Comparing files " + outputFiles[i] + " and " + referenceFiles[i]);
	        			if (ExcelFilesMatch(outputFiles[i], referenceFiles[i], ExcelFilePath))
	        				Report.Log(ReportLevel.Success, outputFiles[i] + " matches " + referenceFiles[i]);
			           	else
			           		throw new ArgumentException(outputFiles[i] + " does not match " + referenceFiles[i]);
	        		}
	        	}        	
        	} 
			catch (ArgumentException ex)
			{
				throw;
			}
			catch (Exception ex)
			{
        	    Report.Log(ReportLevel.Error, ex.Message);
        	    Report.Log(ReportLevel.Info, "Stack trace\r\n" + ex.StackTrace);
        	    throw;
        	}
        }        
        
        
        public static string AddSuffix(string filename, string suffix)
        {
            string fDir = Path.GetDirectoryName(filename);
            string fName = Path.GetFileNameWithoutExtension(filename);
            string fExt = Path.GetExtension(filename);
            return Path.Combine(fDir, String.Concat(fName, suffix, fExt));
        }
        
        
        public static bool ExcelFilesMatch(string filepath1, string filepath2, string ExcelFilePath)
	    {
	        var newRefName = AddSuffix(filepath2, "1");
            Excel.Application xlApp = new Excel.Application();

            var firstRow = 1;
            var row = firstRow;

            try
            {

                Excel.Workbook xlWorkbook1 = xlApp.Workbooks.Open(filepath1);
                File.Copy(filepath2, newRefName, true);
                Excel.Workbook xlWorkbook2 = xlApp.Workbooks.Open(newRefName);
                if (xlWorkbook1.Sheets.Count != xlWorkbook2.Sheets.Count)
                    return false;

                for (int i = 1; i <= xlWorkbook1.Sheets.Count; i++)
                {

                    var xlWorksheet1 = xlWorkbook1.Sheets[i] as Excel._Worksheet;
                    var xlWorksheet2 = xlWorkbook2.Sheets[i] as Excel._Worksheet;

                    var colCount = 1;
                    while ((xlWorksheet1.Cells[row, colCount] as Excel.Range).Value != null)
                        colCount++;

                    while ((xlWorksheet1.Cells[row, 1] as Excel.Range).Value != null && (xlWorksheet2.Cells[row, 1] as Excel.Range).Value != null)
                    {
                        for (int col = 1; col <= colCount; col++)
                        {
                        	var cell1 = xlWorksheet1.Cells[row, col] as Excel.Range;
                        	var cell2 = xlWorksheet2.Cells[row, col] as Excel.Range;
                        	if (cell1 == null || cell2 == null)
                        	{
                        		break;
                        	}
                        	
                        	var cell1val = cell1.Value2;
                        	var cell2val = cell2.Value2;
                        	if ((cell1val == null && cell2val != null) ||  (cell1val != null && cell2val == null))
                        	{
                                Report.Log(ReportLevel.Info, "The spreadsheets do not match at row " + row + " column " + col );    
                                return false;                    		
                        	}
                        	
                        	if (cell1val == null)
                        	{
                        		break;
                        	}
                        	
                        	if (cell1val.ToString() != cell2val.ToString())
                        	{
                                Report.Log(ReportLevel.Info, "The spreadsheets do not match at row " + row + " column " + col );  
                                return false;      
                        	}
                        }
                        row++;
                    }
                }
                return true;
            }
            finally
            {
                while (xlApp.ActiveWorkbook != null)
                {
                    xlApp.ActiveWorkbook.Close(false);
                }

                xlApp.Quit();
                xlApp = null;
                File.Delete(newRefName);
            }
	    }
    }
